var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"이봐, 뭐해! 거기 탄창 좀 챙겨달라니까! 빨리!","JPN":"おい、何してるんだ！　そこの弾倉を取ってくれ！　早く！","ENG":"Hey, look alive! Go get me that mag over there! Hurry!","TWN":"喂，你在幹什麼？ 快給我拿一些彈匣！快點！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"이제… 다 관둬도 되지 않을까?","JPN":"もう……やめてもいいんじゃないか？","ENG":"You think... we can just stop now?","TWN":"事以致此……不如就放棄吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"뭐? 무슨 헛소리야?","JPN":"は？　何バカなことを言ってるんだ？","ENG":"What? What the hell are you talking about?!","TWN":"你在說什麼？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"하늘을 좀 봐. 다 끝났어. 다 부질없다고.","JPN":"空を見ろ。おしまいだ。全部無駄なことなんだよ。","ENG":"Look up at the sky. It's all over. Everything's done for.","TWN":"看看天空。一切都完了，都沒意義了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>로터스, 그림자 전당 내부로부터 특이 에너지 확산 관측.</color>","JPN":"<color=#ffd34c>ロータス、影の殿堂の内部より特異エネルギーの拡散を観測。</color>","ENG":"<color=#ffd34c>In Lotus, detecting abnormal energy spreading from Shadow Palace.</color>","TWN":"<color=#ffd34c>洛德斯，在暗影殿堂內部觀察到特殊的能量擴散。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>분석 결과: 신성 클리파 타입- 타기리온.</color>","JPN":"<color=#ffd34c>分析結果：神聖クリファタイプ-タギリオン。</color>","ENG":"<color=#ffd34c>Analysis results: Divinity Qlipha Type- Thagirion.</color>","TWN":"<color=#ffd34c>分析結果：神聖逆卡巴拉類型-塔基里翁。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>마왕 강림 및 현실 차원계면 붕괴까지… 앞으로 약 30분.</color>","JPN":"<color=#ffd34c>魔王降臨および現実の次元界面の崩壊まで……残りおよそ30分。</color>","ENG":"<color=#ffd34c>Demon Lord's resurrection and the collapse of Normalside's dimension surface in... approximately 30 minutes.</color>","TWN":"<color=#ffd34c>距離魔王降臨與現世次元邊界瓦解……還剩大約30分鐘。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"저게… 대체 뭐야?","JPN":"あれって……一体何だ？","ENG":"What... is that?","TWN":"那到底是……什麼？"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"지금 사람들이 하늘로 솟구치고 있는 건가?","JPN":"人が空へと浮かび上がっているのか？","ENG":"Are people floating up to the sky?","TWN":"人飄到天上了？"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"샤레이드 방어 작전에 참여하고 있는 전 태스크포스 병력들에게 전파한다.","JPN":"シャレードの防御作戦に参加している全タスクフォース兵に伝える。","ENG":"Attention all TASKFORCEs participating in the Charade Defense Operation.","TWN":"所有參與查雷德防禦戰的特遣勢力人員請注意。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 관리국에서 시민 여러분들께 송출하는 행동 요령 안내입니다.</color>","JPN":"<color=#ffd34c>これは管理局から市民の皆様に伝える、行動指針のご案内です。</color>","ENG":"<color=#ffd34c>This is a safety announcement for citizens from the Administration.</color>","TWN":"<color=#ffd34c>這是管理局向各位市民發送的行動要領。</color>"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"현 시간부로 절대 하늘을 쳐다보지 마라.","JPN":"今から絶対に空を見上げるな。","ENG":"As of this moment, do not look up at the sky.","TWN":"從現在起絕對不要抬頭看天空。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"어떤 외침이나 부름이 느껴져도 고개를 들어선 안된다.","JPN":"どんな叫び声や呼ぶ声が聞こえても頭を上げてはならない。","ENG":"No matter what you hear, you must not raise your head.","TWN":"不管聽到怎樣的呼喊或聲音也絕不要抬頭。"},"stage":{"bg":"MS_1203","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>가능한 실내에 머무르시고 실외에서는 절대 하늘을 바라보지 마십시오.</color>","JPN":"<color=#ffd34c>できる限り室内にいて、屋外では決して空を見上げないようにしてください。</color>","ENG":"<color=#ffd34c>Stay indoors as much as possible, and never look up at the sky when outdoors.</color>","TWN":"<color=#ffd34c>請儘量待在室內，在室外絕對不要抬頭看天空。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하늘을 보는 순간 빨려들어가듯 중력을 잃고 하늘로 부상하게 된다고 한다.","JPN":"空を見た瞬間吸い込まれるように重力を失い、浮かび上がっていく。","ENG":"They say looking up will make you lose gravity and get sucked up into the sky.","TWN":"如果抬頭望天空，就會失去重力漂浮到天上。"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"일종의 침식현상이라 생각하면 되겠지만, 이 현상은 이터니움실드로도 막을 수 없다.","JPN":"一種の侵食現象であるが、これはエタニウムシールドでも防げない。","ENG":"I think it's a type of Counterside Effect, but it can't be blocked with the Eternium shield.","TWN":"可以把它看作是一種侵蝕現象，但是用永恆之金防護網也無法阻擋。"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안전을 위해 절대 대피소를 벗어나지 마시고, 관리국의 지침을 따라주십시오.</color>","JPN":"<color=#ffd34c>安全のため決して避難所を離れず、管理局の行動指針に従ってください。</color>","ENG":"<color=#ffd34c>For your safety, follow the Administration's guidelines and do not leave the shelter.</color>","TWN":"<color=#ffd34c>為保安全，千萬不要離開避難所，請聽從管理局的指示。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>해당 지침은 경보해제시까지 유효합니다.</color>","JPN":"<color=#ffd34c>この行動指針は警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>該指令將持續到警報解除。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이상. 무사히 살아서 다시 만나지.","JPN":"以上。無事に生きてまた会おう。","ENG":"Over and out. We'll meet again after we survive.","TWN":"就這樣，我們活著再見面吧。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭔데? 뭔데!? 지금 침식재난상황 아니야? 이불까지 뒤집어쓰고 있으면 어쩌라구!","JPN":"何？　何なの！？　今って侵食災害中じゃないの？　布団までぶってどうしろっていうの！","ENG":"Huh? What?! Isn't this a Corruption Disaster? Why are you putting a blanket over my head?!","TWN":"什麼？！現在不是發生侵蝕災難嗎？怎麼可以躲進被窩裡呢？"},"stage":{"bg":"OFFICE_DETECT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관리국 휴먼들이 실내가 안전하다고 했잖습니까. 여기 얌전히 계십시오, 레이첼.","JPN":"管理局のヒューマンたちが室内が安全と言っています。ここで大人しくするんです、レイチェル。","ENG":"The Administration humans said that it is safe indoors. Stay right here, Rachel.","TWN":"管理局的人說過室內是最安全的，安靜待著吧，瑞秋。"},"stage":{"bg":"OFFICE_DETECT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 상공에 떠다니는 부유체들을 처리하고 오겠습니다.","JPN":"私は上空に浮く浮遊体を処理します。","ENG":"I will go take care of the floating objects in the air.","TWN":"我去處理空中的漂浮物。"},"stage":{"bg":"OFFICE_DETECT","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"주민들은 모두 대피시켰어.","JPN":"住民は全員退避させた。","ENG":"All the residents have been evacuated.","TWN":"所有居民已經疏散完畢。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지하라고 해서 저 하늘로부터 안전할 거란 보장은 없겠지만.","JPN":"地下だからといってあの空から安全だという保障はないが。","ENG":"There's no guarantee that being underground is actually safe from getting sucked up into the sky, though.","TWN":"雖然說不能保證待在地下就一定安全。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"잘 됐군. 이제 저 몰려오는 침식체들만 막아내면 되겠어.","JPN":"ちょうどいい。ならばあの押し寄せてくる侵食体だけ防げばよいな。","ENG":"Good. Now all that is left is to stop the incoming C.O.s.","TWN":"很好，現在我們只需要擋住那些侵蝕體就行了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"국가 단위가 아닌 전세계에 걸친 침식현상이라, 느낌이 좋지 않군요.","JPN":"国レベルではなく、世界中で起きている侵食現象だなんて、悪い予感がしますね。","ENG":"A worldwide Counterside Effect... I got a bad feeling about this.","TWN":"竟然是一場全球性的侵蝕現象，感覺不太妙。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"지키고, 살아남아라.","JPN":"守って、生き残れ。","ENG":"Protect and survive.","TWN":"守護，生存。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"지금은 그걸로 충분하다.","JPN":"今はそれだけで十分だ。","ENG":"That is enough for now.","TWN":"做好這些就足夠了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"갑자기 뭐야? 이런 불길한 경보는 처음 듣는데?","JPN":"いきなり何？　こんな不吉な警報は始めて聞くよ？","ENG":"What's that? I've never heard an ominous alarm like this before.","TWN":"怎麼回事？從沒聽過這麼恐怖的警報？"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아케론의 시스템이 침식파를 감지한 겁니다.","JPN":"アケロンのシステムが侵食波を感知したんです。","ENG":"Acheron's systems have detected Corruption rays.","TWN":"黃泉系統感應到侵蝕波了。"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"침식파? 우주에도 그런 게 있었어?","JPN":"侵食波？　宇宙にもそんなものがあったの？","ENG":"Corruption ray? That's a thing in space too?","TWN":"侵蝕波？宇宙也有這種東西？"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"서둘러, 발키리! 아케론에서 탈옥을 눈치 채고 승강궤도를 끊어버릴 지도 몰라!","JPN":"急いで、ヴァルキリー！　アケロンが脱獄に気づいて昇降レールを切ってしまうかもしれない！","ENG":"Hurry up, Valkyrie! They might catch wind of our escape and cut us off from the orbit!","TWN":"快點，女武神！要是越獄被黃泉發現了電梯會被攔截！"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야! 거기서 뭘 하고 있는…!","JPN":"こら！　そこで何してる……！","ENG":"Hey! What are you doing over the–!","TWN":"喂！你在那裡幹什麼……！"},"stage":{"bg":"CORRIDOR","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐야? 저건?","JPN":"何？　あれ？","ENG":"Huh? What in the world...?","TWN":"那是什麼？"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…지상에 저런 큰 대균열이 있었나?","JPN":"……地上にあれほど大きい大亀裂があったっけ？","ENG":"...Was there always a Grand Dimension Crevice that big down there?","TWN":"……地面上怎麼有那麼巨大的大峽谷？"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"저 곳이라면…. 그림자 전당과 이어져 있겠군.","JPN":"あそこなら……影の殿堂と繋がっているはず。","ENG":"That location... It must be connected to the Shadow Palace.","TWN":"那裡……是通往暗影殿堂的地方。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"방주의 봉인이 풀린 거다.","JPN":"箱舟の封印が解かれたのだ。","ENG":"The Ark's seal has been broken.","TWN":"方舟的封印被解除了。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"허어.","JPN":"へえっ。","ENG":"Huh.","TWN":"唉。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"누구 작품인지, 타이밍 한 번 기가 막히구만.","JPN":"誰がやったんだろ、タイミングがバッチリだね。","ENG":"I don't know whose work this is, but the timing is just perfect.","TWN":"不知道是誰一手策劃的，時機掌握得真是巧妙。"},"stage":{"bg":"MS_1204","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"지금… 무슨 일이 벌어지고 있는 거죠?","JPN":"今……一体何が起きてるんですか？","ENG":"Um... What's going on here?","TWN":"現在……到底發生了什麼事？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘! 지금 하늘을 보면 안돼.","JPN":"ノエル！　今は空を見てはいけない。","ENG":"Noelle! Don't look up!","TWN":"洛艾兒！現在不能看天空。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네, 알겠습니다!","JPN":"はい、わかりました！","ENG":"O-okay!","TWN":"是，我知道了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 왜요?","JPN":"でも、どうしてですか？","ENG":"But why?","TWN":"但為什麼呢？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우리가 한 발 늦었어.","JPN":"私たちがひと足遅かった。","ENG":"We were too late.","TWN":"我們晚了一步。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"클리파 차원 너머의 뭔가가 현실에 간섭하기 시작한 거야.","JPN":"クリファ次元の向こうにある何かが現実に干渉し始めている。","ENG":"Something beyond the Qlipha Dimension is starting to interfere with our world.","TWN":"逆卡巴拉次元彼岸的某個東西開始干擾現實了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"어째서냐.","JPN":"何故だ。","ENG":"What is the meaning of this?","TWN":"為什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"왜 너희 괴물들은 세계의 안위를 위협하고, 또 위협하는 거지?","JPN":"何故、貴様ら化け物は世界の平和を脅かし、また壊そうとしているのだ。","ENG":"Why do you monsters keep threatening to disrupt peace time and time again?","TWN":"為什麼你們這些怪物一再威脅世界的穩定？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마왕은 어찌하여 엘리시온을 간계의 늪에 빠트리고 태양을 빼앗는 악행을 일삼는가!","JPN":"魔王はどのようにしてエリシオンを騙し、策謀に引きずり込み、太陽を奪う悪事を起こさせたのか！","ENG":"Why has the Demon Lord deceived Elysion and taken away our sun with her evil tricks?!","TWN":"魔王用奸計讓艾利森墜入泥沼，還奪走了我們的太陽，為何一而再再而三地犯下惡行！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마왕은 세계를 파멸로 이끌고, 그 마왕을 쓰러트린 대적자는 또다른 마왕으로 태어난다.","JPN":"魔王は世界を破滅へと導き、その魔王を倒した敵対者はまた違う魔王として生まれ変わる。","ENG":"The Demon Lord causes the end of worlds, and the Antagonist who defeats the Demon Lord is reborn as the new Demon Lord.","TWN":"魔王會將世界引向毀滅，而打敗她的對敵者則會重生為另一個魔王。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종말을 목도한 세계는 그 끝없는 악순환의 굴레에 갇혀 무너지고 마는 것이지.","JPN":"終末を目の当たりにした世界はその終わりなき悪循環の輪に閉じ込められ、崩壊してしまうのだ。","ENG":"A world that has witnessed its end inevitably collapses after falling into a vicious cycle.","TWN":"目睹末日的世界會陷入永無止境的惡性循環。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"터무니없는 소리. 마왕을 쓰러트린 건 나다. 네 말대로라면 난 진작에 변했어야했다.","JPN":"バカを言うな。魔王を倒したのは我である。貴様の話が真実であれば我はとっくの昔に変わっているはずだ。","ENG":"Nonsense. I defeated the Demon Lord. According to you, I should have turned into one already.","TWN":"胡說八道。擊敗魔王的人是我，照你所說，我豈不是早就變成魔王了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네가 아니다… 넌 애초에 <color=#ffd34c>대적자가 될 수 없는 존재</color>였으니까.","JPN":"そなたではない……そなたは最初から<color=#ffd34c>敵対者にはなれない存在</color>だったのだ。","ENG":"It was not you... Because you <color=#ffd34c>could never be the Antagonist</color> in the first place.","TWN":"不是你……因為你是<color=#ffd34c>無法成為對敵者的存在</color>。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 곁을 지키던 종자. 그 아이가 바로 대적자다.","JPN":"そなたのそばで見守っていた従者。その子が敵対者である。","ENG":"The myrmidon by your side. That child is the Antagonist.","TWN":"跟在你身邊的那個孩子才是對敵者。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"뭐라고…?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그녀의 누이는 알고 있었다. 자신의 자매가 가진 힘이 종말을 불러오리란 것을.","JPN":"彼女の姉はそれを知っていた。自分の妹が持っている力が世界の終末を呼び起こすということを。","ENG":"Her sister knew. That the power her sister had would bring the end.","TWN":"她姊姊早就知道，自己的妹妹擁有的力量會帶來世界末日。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"흰 서리 꽃은 그녀가 가진 대적자의 힘을 없애기 위함이었지.","JPN":"白い雪の花は彼女が持っている敵対者の力を失くすためのものであった。","ENG":"The White Frost Flower was supposed to be used to remove the power of the Antagonist from her.","TWN":"白霜花是為了消滅她擁有的對敵者力量。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만 얄궂게도, 세계는 인간이 운명을 바꾸는 걸 용납하지 않았다.","JPN":"しかし皮肉なことに、世界は人間が運命を変えようとすることを許さない。","ENG":"But ironically, the world did not allow them to change destiny.","TWN":"但遺憾的是，這個世界不允許人類改變自己的命運。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 미래를 암시했던 이교도는 마물의 침략을 받아 삽시에 몰락했고, 그녀의 누이는 엘리시움 필하모닉의 실험 제물이 되고 말았지.","JPN":"その未来を暗示した異教徒は魔物の侵略で一瞬にして滅び、彼女の姉はエリシウムフィルハーモニーの実験の生贄となってしまった。","ENG":"The pagans who saw the future were devastated by monster invasions, and the child's sister became a test subject for the Elysium Philharmonic.","TWN":"那個暗示未來的異教徒因受到怪物的侵襲而沒落，她的妹妹成為愛樂組織的實驗品。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"감히 나에게 거짓의 마수를 뻗다니. 더 이상의 허언은 용납하지 않으리라.","JPN":"よくも、我に偽りに染まった魔の手を伸ばすとは。これ以上の虚言は許さん。","ENG":"How dare you spit lies at me. I will not tolerate this any longer.","TWN":"竟敢對我撒謊，我不會再容忍了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는 네 자신의 신념에 사로잡혀, 작은 희생이 모두를 구할 수 있을 거라 생각했지.","JPN":"そなたは自分の信念に囚われ、小さな犠牲さえ払えばすべてを救えるはずだと思ったのであろう。","ENG":"You were consumed by your own beliefs and thought that a small sacrifice could save everyone.","TWN":"你沉浸在自己的信念，自以為可以靠微小的犧牲拯救所有人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그리고 그렇게, 네가 방관한 한 명의 죽음이 엘리시온을 멸망으로 이끈 거다.","JPN":"そして、そなたが傍観した一人の死がエリシオンを滅亡へと導くことになったのだ。","ENG":"And thus, the one death you turned a blind eye to has led to the destruction of Elysion.","TWN":"而就是這樣，因為你的袖手旁觀，那一個的死亡給艾利森帶來了滅亡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 입을 다물게 해주마!","JPN":"その口を黙らせてやろう！","ENG":"You shut that mouth!","TWN":"閉上你的嘴！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};